// The strategy ensures that the generated sequence is a valid FOL formula by using the provided parser's validation methods.
// The loop continues until the maximum number of steps is reached or a complete FOL sentence is generated.
// CSD_RATIONALE_END

generated := [];
var hasValid := false;
while stepsLeft > 0 && !hasValid
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
  generated := generated + [next];
  stepsLeft := newSteps;
  hasValid := exists token :: token in generated && parser.ValidNextToken(generated, token);
}
remainingSteps := stepsLeft;

